PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (COUNT(DISTINCT ?tournament) AS ?count)
WHERE {
  ?tournament wdt:P31 wd:Q190257 ;
              wdt:P641 wd:Q2736 ;
              wdt:P1344 / wdt:P17 wd:Q29 .
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (COUNT(DISTINCT ?tournament) AS ?count)
WHERE {
  ?tournament wdt:P31 wd:Q190257 ;
              wdt:P641 wd:Q2736 ;
              wdt:P361 ?olympics ;
              wdt:P1344 ?team .
  ?olympics wdt:P31 wd:Q20233 .
  ?team wdt:P17 wd:Q29 .
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (COUNT(DISTINCT ?olympics) AS ?count)
WHERE {
  ?olympics wdt:P31 wd:Q20233 .
  ?footballTournament wdt:P361 ?olympics ;
                      wdt:P1344 ?team .
  ?team wdt:P17 wd:Q29 .
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (COUNT(DISTINCT ?olympics) AS ?count)
WHERE {
  ?olympics wdt:P31 wd:Q20233 .
  ?event wdt:P641 wd:Q2736 ;
         wdt:P361 ?olympics ;
         wdt:P1344 / wdt:P17 wd:Q29 .
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (COUNT(DISTINCT ?olympics) AS ?count)
WHERE {
