}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (COUNT(DISTINCT ?event) AS ?count)
WHERE {
  ?event wdt:P1344 / wdt:P17 wd:Q29 ;
         wdt:P641 wd:Q2736 ;
         wdt:P361 / wdt:P31 wd:Q20233 .
}
